#include <stdio.h>
int main ()
{
    long long n;
    scanf("%lld",&n);
    if(n%2==0)
    {
        printf("%lld\n",n/2);
        return 0;
    }
    for(long long i=2;(i*i)<=n;i++)
    {
        if(n%i==0)
        {   
            int flag=0;
            for(long long j=2;j<i;j++)
            {
                if(i%j==0)
                {
                    flag=1;
                }
            }
            if(flag==0)
            {
                printf("%lld\n",((n-i)/2)+1);
                return 0;
            }
        }
    }
    printf("1\n");
    return 0;
}

