const BIG_STACK_SIZE: bool = true;
#[allow(dead_code)]
fn main() {
    use std::thread;
    if BIG_STACK_SIZE {
        thread::Builder::new()
            .stack_size(32 * 1024 * 1024)
            .name("solve".into())
            .spawn(solve)
            .unwrap()
            .join()
            .unwrap();
    } else {
        solve();
    }
}
fn solve() {
    let out = stdout();
    let mut out = BufWriter::new(out.lock());
    input!{
        n: i64,
    }
    let mut tot = 0;
    let mut n = n;
    while n%2 == 1 {
        let pd = prime_decomposition(n);
        let mut primes = vec![];
        for k in pd.keys() {
            primes.push(k);
        }
        primes.sort();
        let minp = primes[0];
        n -= minp;
        tot += 1;
    }
    tot += n/2;
    writeln!(out,"{}",tot);
}
#[doc = "O(root(N))"]
fn prime_decomposition(n: i64) -> std::collections::HashMap<i64, i64> {
    fn root_int(n: i64) -> i64 {
        let mut d = 1;
        while d * d <= n {
            d += 1;
        }
        d - 1
    }
    let mut n = n;
    let mut m = std::collections::HashMap::new();
    for i in 2..root_int(n) + 1 {
        while n % i == 0 {
            if !m.contains_key(&i) {
                m.insert(i, 0);
            }
            *m.get_mut(&i).unwrap() += 1;
            n /= i;
        }
    }
    if n != 1 {
        m.insert(n, 1);
    }
    m
}
